import {useState} from 'react';import './LoginForm.css';export default function LoginForm(){const[u,setU]=useState('');const[p,setP]=useState('');const submit=e=>{e.preventDefault();if(!u||!p){alert('Enter Username and Password');return;}alert('Username: '+u+'\nPassword: '+p);setU('');setP('');};return <div className='card p-3'><form onSubmit={submit}><h3>🔐 Login</h3><input className='form-control mt-2' value={u} onChange={e=>setU(e.target.value)} placeholder='Username'/><input type='password' className='form-control mt-2' value={p} onChange={e=>setP(e.target.value)} placeholder='Password'/><button className='btn btn-success mt-3 w-100'>Login</button></form></div>}